mapper.select:
SELECT p.id, p.user_id, p.title, p.content, p.created_at, p.updated_at, u.nickname AS author_name, (SELECT COUNT(*) FROM forum_reply r WHERE r.post_id = p.id) AS reply_count FROM forum_post p LEFT JOIN sys_user u ON p.user_id = u.id
AND p.title LIKE CONCAT('%', #{search}, '%')
ORDER BY p.created_at DESC LIMIT #{offset}, #{pageSize}
